const rows = $input.all();

if (!rows || rows.length === 0) {
  return [{ json: { report: '*Zendesk Ticket Aging Report* -- No aging tickets found today.' } }];
}

const today = new Date().toISOString().split('T')[0];

let lines = [
  '*:ticket: Zendesk Ticket Aging Report -- ' + today + '*',
  'Accounts with open/pending tickets older than 7 days, sorted by ticket count.',
  ''
];

rows.forEach((row, i) => {
  const d = row.json;
  const rank = i + 1;
  const name = d.account_name || 'Unknown';
  const total = d.open_ticket_count || 0;
  const openCount = d.open_count || 0;
  const pendingCount = d.pending_count || 0;
  const oldest = d.oldest_ticket_date || 'N/A';
  lines.push(
    rank + '. *' + name + '* -- ' + total + ' ticket(s) | Open: ' + openCount + ' | Pending: ' + pendingCount + ' | Oldest: ' + oldest
  );
});

lines.push('');
lines.push('_Total accounts affected: ' + rows.length + '_');

return [{ json: { report: lines.join('\n') } }];
